package com.example.bankingapp;

import androidx.appcompat.app.AppCompatActivity;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

public class MainActivity extends AppCompatActivity {

    private EditText accountNumberEditText, amountEditText;
    private Button depositButton, withdrawButton, checkBalanceButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        accountNumberEditText = findViewById(R.id.account_number_edit_text);
        amountEditText = findViewById(R.id.amount_edit_text);
        depositButton = findViewById(R.id.deposit_button);
        withdrawButton = findViewById(R.id.withdraw_button);
        checkBalanceButton = findViewById(R.id.check_balance_button);

        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                String accountNumber = accountNumberEditText.getText().toString();
                String amount = amountEditText.getText().toString();

                if (accountNumber.isEmpty() || amount.isEmpty()) {
                    Toast.makeText(MainActivity.this, "Please fill in all fields", Toast.LENGTH_SHORT).show();
                } else {
                    performDeposit(accountNumber, amount);
                }
            }
        });

        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                String accountNumber = accountNumberEditText.getText().toString();
                String amount = amountEditText.getText().toString();

                if (accountNumber.isEmpty() || amount.isEmpty()) {
                    Toast.makeText(MainActivity.this, "Please fill in all fields", Toast.LENGTH_SHORT).show();
                } else {
                    performWithdrawal(accountNumber, amount);
                }
            }
        });

        checkBalanceButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                String accountNumber = accountNumberEditText.getText().toString();

                if (accountNumber.isEmpty()) {
                    Toast.makeText(MainActivity.this, "Please fill in your account number", Toast.LENGTH_SHORT).show();
                } else {
                    checkBalance(accountNumber);
                }
            }
        });
    }

    private void performDeposit(String accountNumber, String amount) {
        // Simple implementation: increase balance by the deposited amount
        float newBalance = 1000 + Float.parseFloat(amount); // Initial balance is $1000

        Toast.makeText(this, "Deposit successful. New balance: $" + newBalance, Toast.LENGTH_SHORT).show();
    }

    private void performWithdrawal(String accountNumber, String amount) {
        // Simple implementation: decrease balance by the withdrawn amount
        float newBalance = 1000 - Float.parseFloat(amount); // Initial balance is $1000

        if (newBalance < 0) {
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Withdrawal successful. New balance: $" + newBalance, Toast.LENGTH_SHORT).show();
        }
    }

    private void checkBalance(String accountNumber) {
        // Simple implementation: return the initial balance
        float balance = 1000;

        Toast.makeText(this, "Your current balance is: $" + balance, Toast.LENGTH_SHORT).show();
    }
}